function getObjectTypeViewCoreByNameMandatory(objectTypeName, viewName) {
	const viewCore = getObjectTypeViewCoreByName(objectTypeName, viewName);
	if (!viewCore) throw new Error(`View ${viewName} not found for object type ${objectTypeName}`);
	return viewCore;
}
function getObjectTypeViewCoreByName(objectTypeName, viewName) {
	const views = ViewCoreSchema[objectTypeName];
	if (!views) return;
	return views.indexes[viewName] || views.singles[viewName] || views.dataQualities?.[viewName];
}
